window.__QUIZ_DATA__=[{"id":"theory>Biology>2012>PAPER II>PART I>1>a","subject":"Biology","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"Explain briefly four factors that affect the diffusion of substance.","images":[],"marking_scheme":"Factors Affecting the rate of Diffusion  Presence of concentration gradient  when concentration of substance is high the rate of movement off molecules will increase/molecules move from the region of higher concentration to the region of lower concentration; leading to an increase in the rate of diffusion.    - Surface Area  Large surface area will allow more molecules of substance to diffuse .    - State/nature of the diffusing substance: molecules in gaseous state diffuse faster than those of liquids or solid states/molecule in solid state diffuse slower than those of liquid and gas.    - Size of the molecules/particles  The smaller molecules will move/diffuse faster than larger molecules.    - Temperature  increase in temperature increases the movement of molecules/ increases in diffusion/decrease in temperature slows down movement of molecules/decreases diffusion","marks":"8","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>1>b>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"Explain:    Active transport.","images":[],"marking_scheme":"- This is the movement of molecules from a region of low concentration to a region of higher concentration/against a concentration gradient  - across a living membrane;  - using energy from the cell.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>1>b>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Explain:  Transpiration","images":[],"marking_scheme":"- Loss of water in the form of vapor, from the aerial parts of plants.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>1>c","subject":"Biology","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"State four ways by which plants can reduce high rate of transpiration","images":[],"marking_scheme":"- Closure of stomata during the day;  - Reduction of leaf size/leaf modified into spines;  - Dropping of leaves in the dry season;  - Development of thick cuticle;  - Presence of hairs over leave surfaces;  - Presence of sunken stomata.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>1>d","subject":"Biology","year":"2012","type":"Theory","sub_label":"d","group":"","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"State the features of red blood cells and how this features adapt to the cell to perform its function.","images":[],"marking_scheme":"- Biconcave shape/disc-like, increases its surface area for oxygen uptake.  - Elastic membrane; enables it to flow easily through the blood vessels;  - Presence of haemoglobin; for oxygen uptake  - Thin membrane; for easy diffusion of oxygen/carbondioxide.","marks":"4","difficulty":"3"},{"id":"theory>Biology>2012>PAPER II>PART I>2>a","subject":"Biology","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Describe briefly the role of the stomach in digestion.","images":[],"marking_scheme":"- The stomach receives food when the sphincter at the entrance of the stomach relaxes  - The muscular walls of the stomach contract and relax; to churn/mix the food and further break down the particles;  - The stomach produces gastric juices; which contains dilute hydrochloric acid/pepsin/rennin;  - The dilute hydrochloric acid neutralizes the action of the salivary amylase and kills bacteria present to form pepsin;  - The pepsin breaks down the protein to polypeptide/peptides.  - while the rennin coagulates/curdles milk to enhance digestion by pepsin.  - The mucus produced by the stomach wall; lines the wall of the stomach to prevent the action of the acid on the stomach wall  - The mucus produced by the stomach lubricates the movement of the food in the alimentary canal.","marks":"8","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>2>b>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Name three part of plant in which food can be stored","images":[],"marking_scheme":"- Leaves  - Stems  - Roots  - Seeds  - Fruits","marks":"3","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART I>2>b>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Give one example in each case","images":[],"marking_scheme":"Leaves - Onion, garlic, Shallot etc.  Stems - Yam , irish potatoes, Sugar cane, Ginger etc  Root- Cassava, Carrots, Sweet potatoes etc.  Seed-  Groundnut, beans, coconut, cashew  Fruits-  mango, orange, banana, pawpaw, palm nut, apple  etc.","marks":"3","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART I>2>c","subject":"Biology","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"Explain briefly how the level of sugar in the mammalian blood can be regulated","images":[],"marking_scheme":"- the liver controls the blood glucose levels  - it controls excess glucose in the blood to glycogen  - The process is stimulated by the hormone insulin; which is secreted by the pancreas  - When the blood glucose level  falls below normal;  - The pancreas secretes/glucagon  - This stimulates the conversion of glycogen into glucose  - Which is released into the blood.","marks":"6","difficulty":"3"},{"id":"theory>Biology>2012>PAPER II>PART I>3>a>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"Explain briefly this term:    Conservation","images":[],"marking_scheme":"- Conservation is the protection/preservation; and wise management/use of natural resources  - planning and management of resources from loss/waste/harm in order to achieve continuous use/sustainable quality of living for mankind OR conservation is the wise/judicious/intelligent use of cur natural resources to ensure their availability and preserve the quality of the environment.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>3>a>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"Explain briefly this term:  Endangered species","images":[],"marking_scheme":"- Are organisms that have become depleted/rare.  - Due to human activity/natural disaster/epidermic;  - and those habitats have become so disturbed;  - that they may be lost for ever/become extinct.","marks":"3","difficulty":"3"},{"id":"theory>Biology>2012>PAPER II>PART I>3>b>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"State five reasons why conservation of forest is important","images":[],"marking_scheme":"Necessity to Conserve Forests  Economic Importance   Forests produce timber for the construction industry/buildings/furniture/boats/paper;    Domestic  Firewood for charcoal; medicines; gum/resins/rubber/tannins/chemicals/turpentine    Biological Importance  Provide food/shelter for many animals; reduce wind erosion/desertification, serves as wind breaks/checking strong winds; cause precipitation of water from damp air/can increase amount of rainfall in an area; protect source of streams/rivers;help in maintaining CO2/O2 balance in the atmosphere/the plants remove CO2 for photosynthesis/supply O2/purifies the atmosphere    Educational  For ecological studies to prevent certain species from getting extinct    Recreational/Tourism   Serves as tourist attraction","marks":"5","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>3>b>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"State four ways by which forest reserves can be conserved","images":[],"marking_scheme":"- Regulations made to control excessive deforestation, only mature trees should be felled;  - Planting new forest trees/afforestation where they have been completely destroyed;  - Discouraging extensive use of natural forests as a source of timber since animals and some other plants are also destroyed /displaced;  - Replacing harvested/felled mature trees by seedings in plantations/reforestation   - Prevention of forest fires;  - Controlling plant diseases by using pesticides/chemicals to kill pests  - Using trained forest rangers/guards to guard the forests against intruders/fight fires;  - Educating the local population on the dangers of deforestation/carrying out awareness campaigns against deforestation;  - Establishment of forest reserve.","marks":"4","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>3>c>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"What is the importance of decomposers in the ecosystem?","images":[],"marking_scheme":"- They break down organic materials, that are difficult for organisms to digest they return organic matter to the environment in an inorganic form, so that they can be re-assimilated by plants/recycling nutrients.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART I>3>c>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Name one plant and one animal decomposer","images":[],"marking_scheme":"Plant decomposers  Fungi, Rhizopus,Bacteria    Animal decomposers  Earthworms, Termites.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART II>4>a>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"What is a gene?","images":[],"marking_scheme":"- are units of heredity; located in the chromosomes;  - they are responsible for the coding of a particular protein/ to transfer of trait/character from parents to offspring","marks":"2","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART II>4>a>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Differentiate between the terms genotype and phenotype","images":[],"marking_scheme":"- Genotype is the genetic make-up/sum total of genes in an organism that is independent of the environment while a  - Phenotype is all observable features/Outward appearance of the organism that is determined by the environment and the genotype.","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART II>4>b>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain this term:    Hybrid","images":[],"marking_scheme":"- Offspring progeny; produced from a cross between two parents with contrasting; characters","marks":"2","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART II>4>b>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain this term:  Pure breeding","images":[],"marking_scheme":"- A process of producing a particular genotype; over many generations","marks":"2","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART II>4>b>iii","subject":"Biology","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Explain this term:  Nucleotide","images":[],"marking_scheme":"- The basic building block of a nucleic acid; consisting of a ribose/deoxyribose/pentose a phosphate group and a nitrogen base","marks":"2","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART II>4>c>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"In a garden pea seeds, smooth seed coat is  dominant over rough seed coat. With the aid of a genetic diagram, determine the result expected if a homozygous rough pea is crossed with a smooth seed coat plant whose parent were rough coated","images":["data:image/png;base64,"],"marking_scheme":"","marks":"20","difficulty":"3"},{"id":"theory>Biology>2012>PAPER II>PART II>4>c>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"How can vaccination protect the Human body","images":[],"marking_scheme":"- The vaccine/attenuated pathogen is administered into the body  - the body responds by producing copious antibodies  - the next time the body is exposed to the same antigen/infection/pathogen antigen  - The memory cells allow a more rapid and heightened/vigorous response to antibody production  - Protecting the body against future infections","marks":"5","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART II>4>c>iii","subject":"Biology","year":"2012","type":"Theory","sub_label":"iii","group":"","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Differences between antibodies and antigens","images":[],"marking_scheme":"Differences between antibodies and antigens    AntibodyAntigen- A protein moleculemay not be a protein molecule.- Produced in response to a particular foreign substance/anitgenstimulates formation of antibodies- Usually found in the plasma fluid of the blood;usually produced in/introduced into the body- protective in functionsleads to an immune response/immunity","marks":"4","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART II>4>d>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS","question":"Name the causative agents of:  Malaria","images":[],"marking_scheme":"- Plasmodium vivax/Plasmodium/malarial/species","marks":"5","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART II>4>d>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS","question":"Name the causative agents of:  Cholera","images":[],"marking_scheme":"- Vibrio Cholerae","marks":"5","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART II>4>d>iii","subject":"Biology","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : CARRIERS OF MICROORGANISMS","question":"Name the causative agents of:  AIDS","images":[],"marking_scheme":"- Human Immuno-deficiency virus- HIV","marks":"5","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART III>7>a>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Explain this term:    Disease","images":[],"marking_scheme":"A condition in which the normal functions of an organism/part of the body/cell/tissue/organ is impaired/disturbed","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART III>7>a>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"Explain this term:  Symptoms of disease","images":[],"marking_scheme":"- Caused by the presence and irritation  - of a disease causing agent/pathogen","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART III>7>b","subject":"Biology","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"MICROORGANISMS: MAN AND HEALTH : TOWARDS BETTER HEALTH","question":"List two physical and two chemical barriers that prevent pathogens from penetrating the body of an organism","images":[],"marking_scheme":"- Skin  - Hairs  - Cuticle  - Epidermis  - Bark  - Cell wall lining    Chemical barriers  - Mucus  - Saliva  - Tears  - Gastric/HCL and intestinal secretions  - Phenolic compound  - Gums  - Tannins  - Wax  - oily secretions/sebum","marks":"2","difficulty":"3"},{"id":"theory>Biology>2012>PAPER II>PART III>8>a>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Describe epigeal germination of a seed","images":[],"marking_scheme":"- Seed absorbs/imbibes water and swells  - Testa splits and the radicle emerges  - The hypocotyl of the germinating seed elongates;  - pushing the seed out of the soil;  - the cotyledon(s) become exposed to sunlight  - and turn green to photosynthesize;  - the plumule develops into a green shoot  - and the cotyledon(s) dry up/shrink and fall off.","marks":"6","difficulty":"3"},{"id":"theory>Biology>2012>PAPER II>PART III>8>a>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"In a tabular form, state three differences between epigeal germination and hypogeal germination","images":[],"marking_scheme":"Differences between Epigeal and Hypogeal Germination  Epigeal GerminationHypogeal Germination- Hypocotyl elongates- Epicotyl elongates- Cotyledon emerges out of the soil- Cotyledon remains in the soil- Cotyledon(s) turns green/photosynthesize- cotyledons do not photosynthesize- Plumule does not emerge simultaneously with radicle- Plumule emerges simultaneously with radicle- Energy with the radicle from cotyledon - Energy derived fro endosperm.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART III>8>b>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"What is seed dormancy?","images":[],"marking_scheme":"- an inactive period of a seed  - during which growth slows/completely ceases;  - due to certain internal or external factors.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2012>PAPER II>PART III>8>b>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State three ways by which dormancy in seed can be broken.","images":[],"marking_scheme":"- Removal/corrosion of testa;  - treatment of seed with acid/digestive enzymes/water;  - exposure to alternating high and low temperature;  - addition of dormancy-breaking hormones/named hormones;  - exposure to fire;  - exposure to light","marks":"3","difficulty":"2"},{"id":"theory>Biology>2012>PAPER II>PART III>8>c","subject":"Biology","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State six advantages of using contraceptives in human population.","images":[],"marking_scheme":"- it controls birth rate;  - reduces over population;  - promotes maternal health/reduces maternal death;  - promotes infant survival rate;  - enables parents to determine family size;  - prevents unwanted pregnancy;  - enhances good standard of living for the family;  - some prevent STI or STDs.","marks":"6","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>1>a>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"A study was made of four organisms: A, B, C and D of different trophic levels. The number of organisms and biomass of each species was determined. The results are shown in the table below    SpeciesNumber of organismsBiomass of organism(kg)A150050B6000500C15010D351500    Which pf the species is the producer?","images":[],"marking_scheme":"- Specie B is the producer","marks":"1","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>1>a>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"A study was made of four organisms: A, B, C and D of different trophic levels. The number of organisms and biomass of each species was determined. The results are shown in the table below    SpeciesNumber of organismsBiomass of organism(kg)A150050B6000500C15010D351500    Give one reason for the answer in 1(a)(i) above","images":[],"marking_scheme":"- B has the largest  number among the other organisms and in an ecosystem producers are the most numerous","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>1>b","subject":"Biology","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"A study was made of four organisms: A, B, C and D of different trophic levels. The number of organisms and biomass of each species was determined. The results are shown in the table below    SpeciesNumber of organismsBiomass of organism(kg)A150050B6000500C15010D351500    State the role of each of the species in the habitat","images":[],"marking_scheme":"A- Herbivore feeds on B primary consumer and passes the energy to C    B - Producer manufactures food by trapping solar energy which is passed on to herbivores primary consumer    C - Canivore feeds on A and passes its energy to D tertiary Consumer    D - Canivore feeds on C tertiary consumer","marks":"8","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>1>c>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"A study was made of four organisms: A, B, C and D of different trophic levels. The number of organisms and biomass of each species was determined. The results are shown in the table below    SpeciesNumber of organismsBiomass of organism(kg)A150050B6000500C15010D351500    Using the data from the table, draw a labelled diagram to illustrate:  Pyramid of numbers","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>1>c>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"A study was made of four organisms: A, B, C and D of different trophic levels. The number of organisms and biomass of each species was determined. The results are shown in the table below    SpeciesNumber of organismsBiomass of organism(kg)A150050B6000500C15010D351500    Using the data from the table, draw a labelled diagram to illustrate:  Pyramid of biomass","images":["data:image/png;base64,"],"marking_scheme":"","marks":"2","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>1>d>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"A study was made of four organisms: A, B, C and D of different trophic levels. The number of organisms and biomass of each species was determined. The results are shown in the table below    SpeciesNumber of organismsBiomass of organism(kg)A150050B6000500C15010D351500      What organisms would likely constitute A, B, C and D if the habitat was a Marine habitat?","images":[],"marking_scheme":"A - Zooplankton, fish fingerlinhs, copepods, crayfish, shrimps or whales  B - Phytoplankton, Diatoms, Algae or Sea weeds  C - Tilapia, Dogfish, Rayfish, Tiglon, or Herring  D - Shark, Kingfisher, Pelican, Dolphins or Whale","marks":"4","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>1>d>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"A study was made of four organisms: A, B, C and D of different trophic levels. The number of organisms and biomass of each species was determined. The results are shown in the table below    SpeciesNumber of organismsBiomass of organism(kg)A150050B6000500C15010D351500    What organism would likely constitute A, B, C and D if the habitat was a rain forest","images":[],"marking_scheme":"A - Insects, Earthworms, Snails, Tortoise, Monkey, Baboons, Rodents, Grasscutter, Rabbit, Birds or Antelopes  B - Mahogany, Chlorophora sp, Palm tree, Ceiba, Ferns, Bamboo, Trees, Shrubs, Grass or herb.  C - Pangolin, Ant eater, Lizards, Snakes, Toads or Trog  D - Hawk, Kite, Owl, Python","marks":"4","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>1>e","subject":"Biology","year":"2012","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"A study was made of four organisms: A, B, C and D of different trophic levels. The number of organisms and biomass of each species was determined. The results are shown in the table below    SpeciesNumber of organismsBiomass of organism(kg)A150050B6000500C15010D351500      What will be the likely effect on D if the population of A decreases","images":[],"marking_scheme":"- Decrease in the population of A will lead to decrease in C which will lead to a decrease in D as a result of scarcity of food many of D will die off or migrate","marks":"4","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>2>a","subject":"Biology","year":"2012","type":"Theory","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"Two Identical leafy shoots E and F from a shrub, were each connected to a potometer. One was placed under normal laboratory conditions and the other under a fan in the laboratory. The distance moved by each bubble in each potometer was recorded at regular time intervals  The results obtained are shown in the table below:    Study the information in the table carefully and use them to answer questions 2(a) to 2(f).    Time after start of experiment(mins)Distance moved by each bubble (min) Shoot E (nirmal laboratory condition)Shoot F (in the laboratory under the fan)0005351051015818201128251333    Plot a graph, one for each shoot, on the graph sheet provided, with the distance moved by the bubble on the vertical axis(y) and the time on the horizontal axis (x).","images":["data:image/png;base64,"],"marking_scheme":"","marks":"15","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>2>b>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"Under which condition did the bubble move faster?","images":["data:image/png;base64,"],"marking_scheme":"Under fan","marks":"1","difficulty":"1"},{"id":"theory>Biology>2012>PAPER III>2>b>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"Explain the effect of the fan on the shoot","images":[],"marking_scheme":"- Wind or breeze generated by the fan removes water vapour above the stomata  - Creating a greater moisture gradient or transpiration pull  - In the external environment atmosphere of the shoot  - Making water vapour move faster out of the leaf  - Causing more water to be absorbed by the shoot","marks":"3","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>2>b>iii","subject":"Biology","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"What is the aim of the experiment?","images":[],"marking_scheme":"- To study the effect of environment conditions on the rate of transpiration of water loss by shoot","marks":"2","difficulty":"1"},{"id":"theory>Biology>2012>PAPER III>2>c>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Name the physiological process experienced by the leafy shoot","images":[],"marking_scheme":"- Transpiration","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>2>c>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Name one structure of the leaf associated with the process named in 2(c) (i) above","images":[],"marking_scheme":"- Stomata or stoma  - Guard cell (s)","marks":"1","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>a>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Study the diagram below and use them to answer questions 4(a) to 4(e)    Identify the contraceptive methods in D, E, F, G and H","images":["data:image/png;base64,"],"marking_scheme":"D - Tubal ligation or bi-lateral tubal ligation  E - Vasectomy  F - Intra - uterine device or loop  G - Intra - uterine device or coil  H - Condom","marks":"5","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>4>a>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Name the parts labelled I to X","images":["data:image/png;base64,"],"marking_scheme":"I Vas deferens or sperm duct  II Epididymis  III Testis  IV Penis  V Fallopian funnel or Fimbria  VI Uterine wall  VII Cervix  VIII Uterus  IX Ovary  X Fallopian tube or oviduct","marks":"5","difficulty":"3"},{"id":"theory>Biology>2012>PAPER III>4>a>iii","subject":"Biology","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"What are the functions of the parts labelled II, III and X?","images":["data:image/png;base64,"],"marking_scheme":"II - Stores sperm temporarily; produces secretions to keep sperm alive  III - Produces sperm; sex hormones testosterone secretions to keep sperms alive  X - Carries or transport eggs from ovary towards uterus place for fertilization","marks":"3","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>b>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"What materials are in the contraceptives in G and H made of?","images":["data:image/png;base64,"],"marking_scheme":"G = Plastic or stainless steel or copper  H = Rubber or latex","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>b>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"How is the contraceptive in G applied for use","images":["data:image/png;base64,"],"marking_scheme":"- It is inserted into the uterus by a doctor or trained mid-wives","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>c>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State two advantages of G","images":["data:image/png;base64,"],"marking_scheme":"- It prevents implantation or entry of spermatozoa into the uterus, it can stay in the womb for years  - Does not need to be changed often","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>c>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State two disadvantages of G","images":["data:image/png;base64,"],"marking_scheme":"- It can cause bleeding, infection or discomfort  - It can fall off by itself","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>d>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Describe how the contraceptive procedure in E is carried out","images":["data:image/png;base64,"],"marking_scheme":"- A tiny incision or operation is made by a doctor on the man's scrotum and each vas deferens is cut and tied off","marks":"3","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>d>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State one major difference between the procedure in E and F","images":["data:image/png;base64,"],"marking_scheme":"E is permanent or irreversible but F can be reversed  E is surgical, but F is by insertion","marks":"1","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>e>i","subject":"Biology","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Name two advantages of the method in H","images":["data:image/png;base64,"],"marking_scheme":"- Easily accessible  - No hormones or chemicals involved  - Cheap","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>e>ii","subject":"Biology","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Name two disadvantages of the method in H","images":["data:image/png;base64,"],"marking_scheme":"- Not 100% efficient  - Can break or tear","marks":"2","difficulty":"2"},{"id":"theory>Biology>2012>PAPER III>4>e>iii","subject":"Biology","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"What other purposes does the contraceptive in H serve?","images":["data:image/png;base64,"],"marking_scheme":"Acts as a barrier against transmission of STDs","marks":"1","difficulty":"2"}];